=<!DOCTYPE html>
<html lang="de">
<head>
  <meta charset="UTF-8">
</head>

<body style="
  margin: 0;
  padding: 40px 20px;
  font-size: 14px;
  background-color: #2d2e2e;
  background-image: radial-gradient(#3e3e3e 1px, transparent 1px);
  background-size: 12px 12px;
  font-family: Arial, Helvetica, sans-serif;
">

  <div style="
    max-width: 650px;
    margin: 0 auto;
    background-color: #222222;
    border-radius: 8px;
    overflow: hidden;
  ">

    <!-- Header / Logo -->
    <div style="
      background: #040506;
      padding: 20px;
      padding-bottom: 10px;
      text-align: center;
    ">
      <img
        src="https://community.n8n.io/uploads/default/original/2X/a/afa2f499837e9dc9d85724dd8f2eb39bf11a0b5f.png"
        alt="n8n"
        style="width: 120px; height: auto; display: inline-block;"
      >
    </div>

    <!-- Content -->
    <div style="padding: 24px;">

      <!-- Title -->
      <h1 style="
        margin: 0 0 10px;
        padding-bottom: 10px;
        border-bottom: 1px solid #444444;
        font-size: 18px;
        font-weight: 600;
        color: #ffffff;
      ">
        ❌ n8n Workflow Error
      </h1>

      <!-- Workflow Box -->
      <div style="
        background: #2b1d1d;
        border: 1px solid #a73737;
        border-radius: 6px;
        padding: 10px;
        margin: 12px 0;
        text-align: center;
      ">
        <div style="
          font-size: 16px;
          font-weight: 700;
          color: #ff6b6b;
        ">
          {{ $('Error Trigger').item.json.workflow.name }}
        </div>
      </div>

      <!-- Details Table -->
      <table width="100%" cellpadding="0" cellspacing="0">

        <tr>
          <td style="width:170px;color:#999999;font-weight:500;padding:8px 0;">
            Workflow-ID
          </td>
          <td style="color:#ffffff;padding:8px 0;">
            {{ $('Error Trigger').item.json.workflow.id }}
          </td>
        </tr>

        <tr>
          <td style="color:#999999;font-weight:500;padding:8px 0;">
            Execution-ID
          </td>
          <td style="color:#ffffff;padding:8px 0;">
            {{ $('Error Trigger').item.json.execution.id }}
          </td>
        </tr>

        <tr>
          <td style="color:#999999;font-weight:500;padding:8px 0;">
            Retry-Versuche
          </td>
          <td style="color:#ffffff;padding:8px 0;">
            {{ $('Error Trigger').item.json.execution.retryOf }}
          </td>
        </tr>

        <tr>
          <td style="color:#999999;font-weight:500;padding:8px 0;">
            Technische Klasse
          </td>
          <td style="color:#ffffff;padding:8px 0;">
            <strong>{{ $json.technical.class }}</strong>
            <span style="color:#aaaaaa;">
              ({{ $json.technical.subcategory }})
            </span>
          </td>
        </tr>

        <tr>
          <td style="color:#999999;font-weight:500;padding:8px 0;">
            Confidence
          </td>
          <td style="color:#ffffff;padding:8px 0;">
            {{ $json.technical.confidence }}
          </td>
        </tr>

      </table>

      <!-- Error Message -->
      <h4 style="color:#ffffff;margin:24px 0 8px 0;">
        Fehlermeldung
      </h4>

      <div style="
        background: #212830;
        border: 1px solid #444444;
        border-radius: 6px;
        padding: 12px;
        margin: 12px 0;
        color: #d1d7e0;
        font-family: monospace;
        white-space: pre-wrap;
      ">
{{ $('Error Trigger').item.json.execution.error.message }}
      </div>

      <!-- Button -->
      <a href="{{ $('Error Trigger').item.json.execution.url }}"
         style="
           display: inline-block;
           padding: 10px 14px;
           background: #EA4B71;
           color: #ffffff;
           text-decoration: none;
           border-radius: 6px;
           margin-top: 10px;
           font-weight: 600;
         ">
        🔎 Execution in n8n öffnen
      </a>

      <!-- Footer -->
      <div style="
        margin-top: 20px;
        padding-top: 16px;
        border-top: 1px solid #444444;
        color: #999999;
        font-size: 12px;
        text-align: center;
      ">
        n8n Error Handler · Automatische Benachrichtigung
      </div>

    </div>
  </div>

</body>
</html>

