const raw = $input.all()[0]?.json ?? {};

// ✅ RICHTIGER Pfad zur Error Message
const message = raw?.execution?.error?.message ?? "";
const stack   = raw?.execution?.error?.stack ?? "";

// Technische Klassifizierung
function classifyTechnicalError(message = "", stack = "") {
  const msg = String(message).toLowerCase();
  const st  = String(stack).toLowerCase();

  // 🧠 Code Node Fehler (line <number>)
  if (/line\s+\d+/i.test(message)) {
    return {
      class: "logic",
      subcategory: "code_node_error",
      confidence: 0.95
    };
  }

  // Auth
  if (
    msg.includes("401") ||
    msg.includes("403") ||
    msg.includes("unauthorized") ||
    msg.includes("forbidden") ||
    msg.includes("invalid_grant")
  ) {
    return { class: "auth", subcategory: "forbidden_or_token", confidence: 0.95 };
  }

  // Rate limit / throttling
  if (
    msg.includes("rate limit") ||
    msg.includes("ratelimit") ||
    msg.includes("too many requests") ||
    msg.includes("429") ||
    msg.includes("throttle")
  ) {
    return { class: "rate_limit", subcategory: "throttled", confidence: 0.9 };
  }

  // Timeout
  if (msg.includes("timeout") || st.includes("timeout") || msg.includes("etimedout")) {
    return { class: "timeout", subcategory: "upstream_timeout", confidence: 0.85 };
  }

  // Network / DNS / Connection
  if (
    msg.includes("enotfound") ||
    msg.includes("econnreset") ||
    msg.includes("econnrefused") ||
    msg.includes("network") ||
    msg.includes("socket hang up") ||
    msg.includes("getaddrinfo")
  ) {
    return { class: "network", subcategory: "connection", confidence: 0.8 };
  }

  // Data / Missing input
  if (
    msg.includes("nicht gefunden") ||
    msg.includes("not found") ||
    msg.includes("undefined") ||
    msg.includes("cannot read") ||
    msg.includes("null") ||
    msg.includes("missing")
  ) {
    return { class: "data", subcategory: "missing_or_invalid", confidence: 0.85 };
  }

  // Generic logic / exception
  if (
    st.includes("vmcontext") ||
    st.includes("task-runner") ||
    st.includes("code(") ||
    msg.includes("error:") ||
    msg.includes("exception")
  ) {
    return { class: "logic", subcategory: "exception", confidence: 0.75 };
  }

  return { class: "unknown", subcategory: "unclassified", confidence: 0.3 };
}

// ✅ Korrekte Übergabe
const technical = classifyTechnicalError(message, stack);

// ✅ Output: Message + Klassifikation
return [{
  json: {
    technical
  }
}];
